	_ApplyDone = CATFalse;
	_PointVentTypeIndex = -1;
	
	_RevDir1 = 0;
	_RevDir2 = 0;

	_bSingleEdgeRatio = CATFalse;
	_bEdgeVentAxis = CATFalse;
	_EdgePreview = CATFalse;
	_SecondEdgePreview = CATFalse;
	_InvalidElements = 0;

