//-------------------------------------------------------------------------
// BuildGraph()
// Builds Point Vent Creation Dialog
//-------------------------------------------------------------------------
void MRFPointVentCmd::BuildGraph()
{
	AddAnalyseNotificationCB(_pMRFPointVentDlg, _pMRFPointVentDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFPointVentCmd::OnOK, NULL);
	AddAnalyseNotificationCB(_pMRFPointVentDlg, _pMRFPointVentDlg->GetDiaAPPLYNotification(),(CATCommandMethod)& MRFPointVentCmd::ActionOne, NULL);
	AddAnalyseNotificationCB(_pMRFPointVentDlg, _pMRFPointVentDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFPointVentCmd::OnClose, NULL);
	AddAnalyseNotificationCB(_pMRFPointVentDlg, _pMRFPointVentDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFPointVentCmd::OnClose, NULL);
	AddAnalyseNotificationCB(_pMRFPointVentDlg, _pMRFPointVentDlg->GetDiaPREVIEWNotification(), (CATCommandMethod)& MRFPointVentCmd::OnMoveVentDialog, NULL);

	CATDlgCombo* pVentModelType = NULL;
	pVentModelType = _pMRFPointVentDlg->GetVentModelType();
	if (NULL != pVentModelType)
	{
		AddAnalyseNotificationCB(pVentModelType, pVentModelType->GetComboSelectNotification(), (CATCommandMethod)&MRFPointVentCmd::OnVentModelTypeSelection, NULL);
		
		if (0 == _Mode)
		{
			pVentModelType->SetSelect(0);
			_pMRFPointVentDlg->SetFocusOn(pVentModelType);
		}
	}

	Build3DProfileUI();

	_pRefSurfacePathElementAgent = new CATPathElementAgent("RefSurfacePathElementAgent");
	if (_pRefSurfacePathElementAgent)
	{
		CATListOfCATString ListSurfaces = GetSurfaceSelectorTypes();

		_pRefSurfacePathElementAgent->SetOrderedTypeList(ListSurfaces);
		_pRefSurfacePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

	}
	_pRefSurfaceDialogAgent = new CATDialogAgent("RefSurfaceDialogAgent");
	if (_pRefSurfaceDialogAgent)
	{
		CATDlgSelectorList* pReferenceSurfaceSelector = NULL;
		pReferenceSurfaceSelector = _pMRFPointVentDlg->GetReferenceSurface();
		if (NULL != pReferenceSurfaceSelector)
		{
			_pRefSurfaceDialogAgent->AcceptOnNotify(pReferenceSurfaceSelector, pReferenceSurfaceSelector->GetListSelectNotification());
		}
	}
	_pRefSurfaceCtxMenuDlgAgent = new CATDialogAgent("DlgAgentCtxtMenuRefSurface");
	if (_pRefSurfaceCtxMenuDlgAgent)
	{
		CATDlgContextualMenu * pCtxMenuRefSurface = _pMRFPointVentDlg->GetRefSurfaceCtxMenu();
		if (pCtxMenuRefSurface)
		{
			_pRefSurfaceCtxMenuDlgAgent->AcceptOnNotify(pCtxMenuRefSurface, pCtxMenuRefSurface->GetVisibilityNotification());
		}
	}


	CATDialogState* pInitialState = GetInitialState("InitialState");
	pInitialState->AddDialogAgent(_pRefSurfaceDialogAgent);
	pInitialState->AddDialogAgent(_pRefSurfacePathElementAgent);
	pInitialState->AddDialogAgent(_pRefSurfaceCtxMenuDlgAgent);

	_pSurfaceTargetState = AddDialogState("SurfaceTargetState");
	_pSurfaceTargetState->AddDialogAgent(_pRefSurfacePathElementAgent);
	_pSurfaceTargetState->AddDialogAgent(_pRefSurfaceDialogAgent);

	AddTransition(pInitialState, pInitialState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelectorList));
	AddTransition(_pSurfaceTargetState, pInitialState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelectorList));
	if (0 == _Mode || (1 == _Mode && 5 != _PointVentTypeIndex))
	{
		AddTransition(pInitialState, _pSurfaceTargetState, IsOutputSetCondition(_pRefSurfacePathElementAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelection));
		AddTransition(pInitialState, pInitialState, IsOutputSetCondition(_pRefSurfaceCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuSurfaceSelection));
	}

	if (NULL != pInitialState && (0 == _Mode || (1 == _Mode && 0 == _PointVentTypeIndex)))
	{
		//State Chart to build Single Edge Method Dialog UI
		BuildSingleEdgeMethodUI(pInitialState);
	}
	
	if (NULL != pInitialState && (0 == _Mode || (1 == _Mode && 1 == _PointVentTypeIndex)))
	{
		//State Chart to build Dual Edge Method Dialog UI
		BuildDualEdgeMethodUI(pInitialState);
	}

	if (NULL != pInitialState && (0 == _Mode || (1 == _Mode && 2 == _PointVentTypeIndex)))
	{
		//State Chart to build Curve and Two Edge Method Dialog UI
		BuildCurveEdgeMethodUI(pInitialState);
	}

	if (NULL != pInitialState && (0 == _Mode || (1 == _Mode && 3 == _PointVentTypeIndex)))
	{
		//State Chart to build Edge and Vent Method Dialog UI
		BuildEdgeVentMethodUI(pInitialState);
	}

	if (NULL != pInitialState && (0 == _Mode || (1 == _Mode && 4 == _PointVentTypeIndex)))
	{
		//State Chart to build Between Two Vents Method Dialog UI
		BuildTwoVentMethodUI(pInitialState);
	}

	if (NULL != pInitialState && (1 == _Mode && 5 == _PointVentTypeIndex))
	{
		//State Chart to build Segment Vent Dialog UI
		BuildSegmentVentUI(pInitialState);
	}

	if (1 == _Mode && _InvalidElements > 0)
	{
		CATUnicodeString strMessage = "Some of the input elements does not exist anymore.\n";
		strMessage.Append("Please reselect correct Inputs.");
		ShowErrorMessage(strMessage);
	}

	if (1 == _Mode && 5 != _PointVentTypeIndex)
	{
		_pMRFPointVentDlg->SetPREVIEWSensitivity(CATDlgEnable);
	}

	if (0 == _Mode && NULL_var != _spVentGeomSet)
	{
		SetPreviousReferenceSurface();
	}
}

//-------------------------------------------------------------------------
// ActionOne ()
// Launched on clicking Apply
//-------------------------------------------------------------------------
void MRFPointVentCmd::ActionOne(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (!_ApplyDone)
	{
		if (!!_pMRFPointVentDlg)
		{
			if (ValidateSelections(_PointVentTypeIndex))
			{
				ClearAllSelections();

				CATDlgCombo* pVentModelTypeCombo = _pMRFPointVentDlg->GetVentModelType();
				if (!!pVentModelTypeCombo && CATDlgEnable == pVentModelTypeCombo->GetSensitivity())
				{
					pVentModelTypeCombo->SetSensitivity(CATDlgDisable);
				}

				if (SUCCEEDED(CreateOrUpdatePointVent(_PointVentTypeIndex)))
				{
					_ApplyDone = CATTrue;
					if (0 == _Mode)
					{
						_Mode = 1;
					}
					if (5 != _PointVentTypeIndex && CATDlgDisable == _pMRFPointVentDlg->GetPREVIEWSensitivity())
					{
						_pMRFPointVentDlg->SetPREVIEWSensitivity(CATDlgEnable);
					}
				}
			}
		}		
	}
	return;
}

//-------------------------------------------------------------------------
// OnClose ()
// Launched while closing the dialog or clicking cancel
//-------------------------------------------------------------------------
void MRFPointVentCmd::OnClose(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData   iUsefulData)
{
	if (_ApplyDone)
		this->ExecuteUndoAtEnd();

	if (!!_pMRFPointVentDlg)
		_pMRFPointVentDlg->SetVisibility(CATDlgHide);

	RequestDelayedDestruction();
}

//-------------------------------------------------------------------------
// OnOK ()
// Launched on click of OK
//-------------------------------------------------------------------------
void MRFPointVentCmd::OnOK(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData   iUsefulData)
{
	if (!_ApplyDone)
		this->ActionOne(ipCommand, ipNotification, iUsefulData);

		if (!!_pMRFPointVentDlg)
			_pMRFPointVentDlg->SetVisibility(CATDlgHide);

		RequestDelayedDestruction();

	return;
}

void MRFPointVentCmd::OnMoveVentDialog(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (1 == _Mode && 5 != _PointVentTypeIndex && !!_pMRFVentServices)
	{
		_pMRFMoveVentsDlg = new MRFMoveVentsDlg(_pMRFPointVentDlg);
		_spPointVentList.RemoveAll();
		if (0 == _PointVentTypeIndex || 2 == _PointVentTypeIndex || 4 == _PointVentTypeIndex)
		{
			MRFIPointVentSet * pMRFPointVentSet = NULL;
			_pMRFVentServices->GetPointVentSetObject(pMRFPointVentSet);

			if (NULL != pMRFPointVentSet)
			{
				pMRFPointVentSet->GetListOfVents(_spPointVentList);
				pMRFPointVentSet->Release();  pMRFPointVentSet = NULL;
			}
		}
		else if (1 == _PointVentTypeIndex || 3 == _PointVentTypeIndex || 6 == _PointVentTypeIndex)
		{
			MRFIPointVent * pMRFPointVent = NULL;
			_pMRFVentServices->GetPointVentObject(pMRFPointVent);
			if (NULL != pMRFPointVent)
			{
				_spPointVentList.Append(pMRFPointVent);
			}
		}
		if (!!_pMRFMoveVentsDlg && _spPointVentList.Size() > 0)
		{
			AddAnalyseNotificationCB(_pMRFMoveVentsDlg, _pMRFMoveVentsDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFPointVentCmd::OnMoveVentClose, NULL);
			AddAnalyseNotificationCB(_pMRFMoveVentsDlg, _pMRFMoveVentsDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFPointVentCmd::OnMoveVentClose, NULL);
			AddAnalyseNotificationCB(_pMRFMoveVentsDlg, _pMRFMoveVentsDlg->GetDiaAPPLYNotification(), (CATCommandMethod)& MRFPointVentCmd::OnMoveVentApply, NULL);
			AddAnalyseNotificationCB(_pMRFMoveVentsDlg, _pMRFMoveVentsDlg->GetDiaPREVIEWNotification(), (CATCommandMethod)& MRFPointVentCmd::OnMoveVentReset, NULL);

			CATDlgMultiList * pMultiList = NULL;
			CATDlgContextualMenu * pCtxMenuMultiList = NULL;
			_pMRFMoveVentsDlg->BuildMultiList(_spPointVentList.Size(), 5);
			
			pMultiList = _pMRFMoveVentsDlg->GetMultiList();
			if (!!pMultiList)
			{
				AddAnalyseNotificationCB(pMultiList, pMultiList->GetListSelectNotification(), (CATCommandMethod)& MRFPointVentCmd::OnMoveVentMultiListSelect, NULL);

				BuildMoveVentsMultiList(_spPointVentList);
				_pMRFMoveVentsDlg->SetVisibility(CATDlgShow);
			}
			pCtxMenuMultiList = _pMRFMoveVentsDlg->GetCtxMenu();
			if (!!pCtxMenuMultiList)
			{
				AddAnalyseNotificationCB(pCtxMenuMultiList, pCtxMenuMultiList->GetVisibilityNotification(), (CATCommandMethod)&MRFPointVentCmd::BuildMoveVentsContextMenu, iUsefulData);
			}
		}
	}

	return;
}

void MRFPointVentCmd::OnMoveVentMultiListSelect(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData   iUsefulData)
{
	if (!!_pMRFMoveVentsDlg)
	{
		CATDlgMultiList * pMultiList = _pMRFMoveVentsDlg->GetMultiList();
		if (!!pMultiList)
		{
			int SelectedRow = -1;
			pMultiList->GetSelect(&SelectedRow, 1);

			if (SelectedRow >= 0 && SelectedRow < _spPointVentList.Size())
			{
				CATBaseUnknown_var spSelectedPointVent = _spPointVentList[SelectedRow + 1];
				if (NULL_var != spSelectedPointVent)
				{
					CATPathElement * pPathElement = NULL;
					BuildPathElementFromObject(spSelectedPointVent, pPathElement);
					if (NULL != pPathElement && NULL != _pHSO)
					{

						_pHSO->Empty();
						if (0 == _pHSO->IsMember(pPathElement))
							_pHSO->AddElement(pPathElement);
						pPathElement->Release(); pPathElement = NULL;
					}
				}
			}
		}
	}


}

void MRFPointVentCmd::OnMoveVentReset(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData   iUsefulData)
{
	if (!!_pMRFMoveVentsDlg)
	{
		CATDlgMultiList * pMultiList = NULL;
		pMultiList = _pMRFMoveVentsDlg->GetMultiList();
		if (!!pMultiList)
		{
			int NbRows = pMultiList->GetLineCount();
			for (int i = 0; i < NbRows; i++)
			{
				CATUnicodeString strZero;
				strZero.BuildFromNum(0.0);
				pMultiList->SetColumnItem(3, strZero, i, CATDlgDataModify);
				pMultiList->SetColumnItem(4, strZero, i, CATDlgDataModify);
			}
		}
		OnMoveVentApply(ipCommand, ipNotification, iUsefulData);
	}

}
