//-------------------------------------------------------------------------
// OnVentModelTypeSelection ()
// Launched when selection is done on Vent Model Type Selector List
//-------------------------------------------------------------------------
void MRFPointVentCmd::OnVentModelTypeSelection(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (NULL != _pHSO)
	{
		_pHSO->Empty();
	}

	if (!!_pMRFPointVentDlg && CATDlgShow == _pMRFPointVentDlg->GetVisibility())
	{

		if (_EdgePreview)
			PreviewEdgeDirection(ipCommand, ipNotification, iUsefulData);

		if (_SecondEdgePreview)
			PreviewSecondEdgeDirection(ipCommand, ipNotification, iUsefulData);

		if (0 == _Mode)
		{
			_RevDir1 = 0;
			_RevDir2 = 0;
		}

		CATDlgCombo* pVentModelTypeCombo = NULL;
		pVentModelTypeCombo = _pMRFPointVentDlg->GetVentModelType();
		_PointVentTypeIndex = pVentModelTypeCombo->GetSelect();
		if (0 == _Mode && 5 == _PointVentTypeIndex)
		{
			pVentModelTypeCombo->SetSelect(_PointVentTypeIndex - 1, 0);
			_PointVentTypeIndex = _PointVentTypeIndex - 1;
		}
			

		if (_PointVentTypeIndex > -1)
			_pMRFPointVentDlg->ShowVentTypeFrame(_PointVentTypeIndex);


		CATDlgSelectorList* pReferenceSurfaceSelector = _pMRFPointVentDlg->GetReferenceSurface();
		if (NULL != pReferenceSurfaceSelector)
		{
			int select[1] = { 0 };
			pReferenceSurfaceSelector->GetSelect(select, 1);
			pReferenceSurfaceSelector->SetSelect(select, 1, 1);

			_pMRFPointVentDlg->SetFocusOnSelectorList(pReferenceSurfaceSelector);
		}
		ClearAllSelections();

	}
}

