//-------------------------------------------------------------------------
// FeaturizeSubElement ()
// Featurizes the selected sub element
//-------------------------------------------------------------------------
void MRFPointVentCmd::FeaturizeSubElement(CATCell_var ispSubElement, CATBaseUnknown_var ispSupportObject, CATIMmiMechanicalFeature_var & ospObjectFeature)
{
	if (NULL_var != ispSubElement && NULL_var != ispSupportObject)
	{
		CATBody_var spElementBody;
		MRFGenericUtils::GetBodyOfObject(ispSupportObject, spElementBody);
		CATIMmiUseBRepAccess_var spBRepAccess;
		CATIMmiUseBRepDecodeServices_var spBRepDecodeServices;
		CATMmiUseServicesFactory::CreateBRepDecodeServices(spBRepDecodeServices);

		HRESULT rc = spBRepDecodeServices->DecodeCellInBody(spBRepAccess, ispSubElement, spElementBody);
		CATIMmiUseMfBRep_var spBRepFeature;
		if (NULL_var != spBRepAccess)
		{
			CATIMmiUseFeaturize * pIFeaturize = NULL;
			rc = spBRepAccess->QueryInterface(IID_CATIMmiUseFeaturize, (void **)&pIFeaturize);
			if ((SUCCEEDED(rc)) && (NULL != pIFeaturize))
			{
				//CATMfFeaturizeMode iMode = MfNoDuplicateFeature | MfPermanentBody | MfLastFeatureSupport;
				CATMfFeaturizeMode iMode = MfPermanentBody | MfLastFeatureSupport | MfRelimitedFeaturization;
				pIFeaturize->Featurize(spBRepFeature, iMode, CATMmrRelimited);

				if (NULL_var != spBRepFeature)
				{
					if (spBRepFeature != NULL_var)
					{
						CATIUseEntity * piPartEntity = NULL;
						rc = spBRepFeature->QueryInterface(IID_CATIUseEntity, (void**)&piPartEntity);
						if (SUCCEEDED(rc))
						{
							rc = DataCommonProtocolServices::Update(piPartEntity);
							piPartEntity->Release();
							piPartEntity = NULL;
						}
					}
					ospObjectFeature = spBRepFeature;
					spBRepFeature->Release(); spBRepFeature = NULL_var;
				}
				pIFeaturize->Release();
				pIFeaturize = NULL;
			}
		}
	}
}

//-------------------------------------------------------------------------
// BuildFromPathElement ()
// Sets the name of the selected object in the Dialog
// Returns the CATIMmiMechanicalFeature of the selected object
//-------------------------------------------------------------------
CATBoolean MRFPointVentCmd::BuildFromPathElement(CATPathElement * ipSelectedPathElement, CATDlgSelectorList * ipSelectedDialog, CATIMmiMechanicalFeature_var & ospFeatureObject)
{
	if (!!_pMRFPointVentDlg && NULL != ipSelectedPathElement && NULL != ipSelectedDialog)
	{
		if (NULL != _pHSO)
		{
			_pHSO->Empty();
			if (0 == _pHSO->IsMember(ipSelectedPathElement))
				_pHSO->AddElement(ipSelectedPathElement);
		}

		CATUnicodeString strEdgeName = GetObjectNameFromPathElement(ipSelectedPathElement, ospFeatureObject);
		if (0 < strEdgeName.GetLengthInChar() && NULL_var != ospFeatureObject)
		{
			ipSelectedDialog->ClearLine();
			ipSelectedDialog->SetLine(strEdgeName);
			_pMRFPointVentDlg->SetFocusOnSelectorList(ipSelectedDialog);
		}
	}
	return CATTrue;
}

//-------------------------------------------------------------------------
// ClearSelection ()
// Clears the selected Dialog
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::ClearSelection(CATPathElement * ipSelectedPathElement, CATDlgSelectorList * ipSelectedDialog)
{
	if (!!_pMRFPointVentDlg && NULL != ipSelectedPathElement && NULL != ipSelectedDialog)
	{
		if (NULL != _pHSO && 0 != _pHSO->IsMember(ipSelectedPathElement))
		{
			_pHSO->RemoveElement(ipSelectedPathElement);
		}

		ipSelectedDialog->ClearSelect();
		ipSelectedDialog->ClearLine();
		ipSelectedDialog->SetLine("No Edge Selected");
		_pMRFPointVentDlg->SetFocusOnSelectorList(ipSelectedDialog);
	}

	_ApplyDone = CATFalse;

	return CATTrue;
}

