//-------------------------------------------------------------------------
// On3DVentProfileModify ()
// Launched when 3D Vent Profile Type is changed
//-------------------------------------------------------------------------
void MRFPointVentCmd::On3DVentProfileModify(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (!!_pMRFPointVentDlg && CATDlgShow == _pMRFPointVentDlg->GetVisibility())
	{
		CATDlgCombo* p3DPointVentProfile = NULL;
		p3DPointVentProfile = _pMRFPointVentDlg->Get3DVentProfileType();
		if (NULL != p3DPointVentProfile)
		{
			int iVentProfileIndex = p3DPointVentProfile->GetSelect();
			if (iVentProfileIndex > -1)
			{
				_pMRFPointVentDlg->ShowSelected3DVentProfileFrame(iVentProfileIndex);
			}
		}
		if (0 == _Mode)
		{
			_RevDir1 = 0;
			_RevDir2 = 0; 
		}
		_ApplyDone = CATFalse;
	}
}

