//-------------------------------------------------------------------------
// OnSurfaceSelection ()
// Launched when user selects as Surface
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::OnSurfaceSelection(void * iData)
{
	if (NULL != _pRefSurfacePathElementAgent)
	{
		_pRefSurfacePathElement = _pRefSurfacePathElementAgent->GetValue();

		if (!!_pRefSurfacePathElement)
		{
			if (NULL != _pHSO)
			{
				_pHSO->Empty();
				if (0 == _pHSO->IsMember(_pRefSurfacePathElement))
					_pHSO->AddElement(_pRefSurfacePathElement);
			}

			CATIMmiMechanicalFeature_var spSurfaceObject;
			CATUnicodeString strSurfaceName = GetObjectNameFromPathElement(_pRefSurfacePathElement, spSurfaceObject, 2);

			if (NULL_var != spSurfaceObject)
			{
				_spReferenceSurface = spSurfaceObject;
				
				/*/BuildPathElementFromObject(_spReferenceSurface, _pRefSurfacePathElement);*/
				GetGeoFactory();
			}

			if (!!_pMRFPointVentDlg)
			{
				CATDlgSelectorList* pReferenceSurfaceSelector = _pMRFPointVentDlg->GetReferenceSurface();
				if (NULL != pReferenceSurfaceSelector)
				{
					
					pReferenceSurfaceSelector->ClearLine();
					pReferenceSurfaceSelector->SetLine(strSurfaceName);
					_pMRFPointVentDlg->SetFocusOnSelectorList(pReferenceSurfaceSelector);
				}
			}
			DynamicTrantition();

		}
	}

	if (!!_pRefSurfacePathElementAgent)
		_pRefSurfacePathElementAgent->InitializeAcquisition();


	return CATTrue;
}

