//-------------------------------------------------------------------------
// OnCtxMenuSurfaceSelection ()
// Launched when Context menu on Surface Selector is clicked
//-------------------------------------------------------------------------
void MRFPointVentCmd::OnCtxMenuClearRefSurface(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	char * pstrAction = (char *)iUsefulData;
	
	CATString strAction(pstrAction);

	if (0 == strAction.Compare("ClearSelection"))
	{
		if (NULL != _pHSO && NULL != _pRefSurfacePathElement && 0 != _pHSO->IsMember(_pRefSurfacePathElement))
		{
			_pHSO->RemoveElement(_pRefSurfacePathElement);
		}

		_pRefSurfacePathElement = NULL;
		_spReferenceSurface = NULL_var;
		_ApplyDone = CATFalse;

		if (_EdgePreview)
			PreviewEdgeDirection(ipCommand, ipNotification, iUsefulData);

		if (_SecondEdgePreview)
			PreviewSecondEdgeDirection(ipCommand, ipNotification, iUsefulData);

		CATDlgSelectorList* pSelectorListRefSurface = _pMRFPointVentDlg->GetReferenceSurface();
		if (pSelectorListRefSurface)
		{
			pSelectorListRefSurface->ClearSelect();
			pSelectorListRefSurface->ClearLine();
			pSelectorListRefSurface->SetLine("No Surface Selected");
			_pMRFPointVentDlg->SetFocusOnSelectorList(pSelectorListRefSurface);
		}

	}
	return;
}


//-------------------------------------------------------------------------
// BuildSingleEdgeMethodUI ()
// Build Single Edge Method Vent Type Dialog Components
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::BuildSingleEdgeMethodUI(CATDialogState *& ipInitialState)
{
	if (NULL != ipInitialState && NULL != _pSurfaceTargetState)
	{
		_pSingleEdgeRefEdgePathElementAgent = new CATPathElementAgent("SingleEdgeRefEdgePathElementAgent");
		if (_pSingleEdgeRefEdgePathElementAgent)
		{
			CATListOfCATString ListEdgeTypes = GetEdgeOrCurveSelectorTypes();

			_pSingleEdgeRefEdgePathElementAgent->SetOrderedTypeList(ListEdgeTypes);
			_pSingleEdgeRefEdgePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pSingleEdgeRefEdgeDialogAgent = new CATDialogAgent("SingleEdgeRefEdgeDialogAgent");
		if (_pSingleEdgeRefEdgeDialogAgent)
		{
			CATDlgSelectorList* pSingleEdgeRefEdgeSelector = NULL;
			pSingleEdgeRefEdgeSelector = _pMRFPointVentDlg->GetSingleEdgeRefEdge();
			if (NULL != pSingleEdgeRefEdgeSelector)
			{
				_pSingleEdgeRefEdgeDialogAgent->AcceptOnNotify(pSingleEdgeRefEdgeSelector, pSingleEdgeRefEdgeSelector->GetListSelectNotification());
			}
		}

		_pSingleEdgeRefEdgeCtxMenuDlgAgent = new CATDialogAgent("DlgAgentCtxtMenuSingleEdgeRefEdge");
		if (_pRefSurfaceCtxMenuDlgAgent)
		{
			CATDlgContextualMenu * pCtxMenuRefEdge = _pMRFPointVentDlg->GetSingleEdgeRefEdgeCtxMenu();
			if (pCtxMenuRefEdge)
			{
				_pSingleEdgeRefEdgeCtxMenuDlgAgent->AcceptOnNotify(pCtxMenuRefEdge, pCtxMenuRefEdge->GetVisibilityNotification());
			}
		}

		CATDlgPushButton* pPushButton = NULL;
		pPushButton = _pMRFPointVentDlg->GetSingleEdgeOffsetDir();
		if (NULL != pPushButton)
		{
			AddAnalyseNotificationCB(pPushButton, pPushButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFPointVentCmd::PushReverseDirection1, NULL);
		}

		CATDlgPushButton* pPreview = NULL;
		pPreview = _pMRFPointVentDlg->GetSingleEdgePreview();
		if (NULL != pPreview)
		{
			AddAnalyseNotificationCB(pPreview, pPreview->GetPushBActivateNotification(), (CATCommandMethod)&MRFPointVentCmd::PreviewEdgeDirection, NULL);
		}

		CATDlgSpinner* pOffsetDist = NULL;
		pOffsetDist = _pMRFPointVentDlg->GetSingleEdgeOffsetDistance();
		if (NULL != pOffsetDist)
		{
			AddAnalyseNotificationCB(pOffsetDist, pOffsetDist->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::SetPointVentModified, NULL);
		}

		CATDlgSpinner* NbOfDivisions = NULL;
		NbOfDivisions = _pMRFPointVentDlg->GetSingleEdgeNbOfDivisions();
		if (NULL != NbOfDivisions)
		{
			AddAnalyseNotificationCB(NbOfDivisions, NbOfDivisions->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::SetPointVentModified, NULL);
		}

		CATDlgSpinner* pRatio = NULL;
		pRatio = _pMRFPointVentDlg->GetSingleEdgeRatio();
		if (NULL != pRatio)
		{
			AddAnalyseNotificationCB(pRatio, pRatio->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::SetPointVentModified, NULL);
		}
		
		CATDlgRadioButton* pNbRadio = _pMRFPointVentDlg->GetSingleEdgeNbRadio();
		if (NULL != pNbRadio)
		{
			CATCommandClientData SingleEdgeData("SingleEdge");
			AddAnalyseNotificationCB(pNbRadio, pNbRadio->GetRadBModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::OnRadioChange, SingleEdgeData);
			if (0 == _Mode)
				pNbRadio->SetState(CATDlgCheck, 1);
		}

		ipInitialState->AddDialogAgent(_pSingleEdgeRefEdgeDialogAgent);
		ipInitialState->AddDialogAgent(_pSingleEdgeRefEdgeCtxMenuDlgAgent);
		//ipInitialState->AddDialogAgent(_pSingleEdgeRefEdgePathElementAgent);
		
		_pSurfaceTargetState->AddDialogAgent(_pSingleEdgeRefEdgeDialogAgent);

		CATDialogState * pSingleEdgeReferenceEdgeState = AddDialogState("SingleEdgeReferenceEdge");
		pSingleEdgeReferenceEdgeState->AddDialogAgent(_pSingleEdgeRefEdgeDialogAgent);
		pSingleEdgeReferenceEdgeState->AddDialogAgent(_pSingleEdgeRefEdgePathElementAgent);
		pSingleEdgeReferenceEdgeState->AddDialogAgent(_pRefSurfaceDialogAgent);
		pSingleEdgeReferenceEdgeState->AddDialogAgent(_pSingleEdgeRefEdgeCtxMenuDlgAgent);
		pSingleEdgeReferenceEdgeState->AddDialogAgent(_pRefSurfaceCtxMenuDlgAgent);

		AddTransition(ipInitialState, pSingleEdgeReferenceEdgeState, IsOutputSetCondition(_pSingleEdgeRefEdgeDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSingleEdgeReferenceEdgeSelectorList));
		AddTransition(_pSurfaceTargetState, pSingleEdgeReferenceEdgeState, IsOutputSetCondition(_pSingleEdgeRefEdgeDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSingleEdgeReferenceEdgeSelectorList));
		AddTransition(pSingleEdgeReferenceEdgeState, pSingleEdgeReferenceEdgeState, IsOutputSetCondition(_pSingleEdgeRefEdgeDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSingleEdgeReferenceEdgeSelectorList));
		//AddTransition(pSingleEdgeReferenceEdgeState, ipInitialState, IsOutputSetCondition(_pSingleEdgeRefEdgeDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSingleEdgeReferenceEdgeSelectorList));

		AddTransition(pSingleEdgeReferenceEdgeState, pSingleEdgeReferenceEdgeState, IsOutputSetCondition(_pSingleEdgeRefEdgeCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuSingleEdgeRefSelection));
		AddTransition(ipInitialState, pSingleEdgeReferenceEdgeState, IsOutputSetCondition(_pSingleEdgeRefEdgeCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuSingleEdgeRefSelection));
		AddTransition(pSingleEdgeReferenceEdgeState, ipInitialState, IsOutputSetCondition(_pRefSurfaceCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuSurfaceSelection));

		AddTransition(pSingleEdgeReferenceEdgeState, ipInitialState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelectorList));
		AddTransition(pSingleEdgeReferenceEdgeState, pSingleEdgeReferenceEdgeState, IsOutputSetCondition(_pSingleEdgeRefEdgePathElementAgent), Action((ActionMethod)&MRFPointVentCmd::OnSingleEdgeReferenceEdgeSelection));

	}
	return CATTrue;
}

