//-------------------------------------------------------------------------
// OnSingleEdgeReferenceEdgeSelection ()
// Launched when user selects as Reference Edge in Single Edge Method
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::OnSingleEdgeReferenceEdgeSelection(void * iData)
{
	if (!!_pMRFPointVentDlg && NULL != _pSingleEdgeRefEdgePathElementAgent)
	{
		_pSingleEdgeRefEdgePathElement = _pSingleEdgeRefEdgePathElementAgent->GetValue();

		CATDlgSelectorList* pReferenceEdge = _pMRFPointVentDlg->GetSingleEdgeRefEdge();

		if (!!_pSingleEdgeRefEdgePathElement && NULL != pReferenceEdge)
		{
			CATIMmiMechanicalFeature_var spEdgeFeatureObject;
			BuildFromPathElement(_pSingleEdgeRefEdgePathElement, pReferenceEdge, spEdgeFeatureObject);
			
			double NbOfDivisions = _pMRFPointVentDlg->GetSelectedNbOfDivisions(0);
			_RevDir1 = 0;
			if (_EdgePreview)
				PreviewEdgeDirection();
				//PreviewEdgeDirection(ipCommand, ipNotification, iUsefulData);
			if (!ValidateSelectedEdge(spEdgeFeatureObject, NbOfDivisions))
			{
				CATUnicodeString strMessage = "Selected Edge does not completely lie on the selected Surface.\n";
				strMessage.Append("Please reselect Inputs.");
				ShowErrorMessage(strMessage);

				ClearSelection(_pSingleEdgeRefEdgePathElement, pReferenceEdge);
				_pSingleEdgeRefEdgePathElement = NULL;
				_spSignleEdgeRefEdge = NULL_var;
				_pMRFPointVentDlg->SetFocusOnSelectorList(pReferenceEdge);

				_ApplyDone = CATFalse;
			}
			else
			{
				if (NULL_var != _spSignleEdgeRefEdge)
				{
					_spSignleEdgeRefEdge = NULL_var;
				}
				_spSignleEdgeRefEdge = spEdgeFeatureObject;
				PreviewEdgeDirection();
				//PreviewEdgeDirection(ipCommand, ipNotification, iUsefulData);
			}

		}
	}

	if (!!_pSingleEdgeRefEdgePathElementAgent)
		_pSingleEdgeRefEdgePathElementAgent->InitializeAcquisition();


	return CATTrue;
}

