			{
				CATUnicodeString  strClearSelection = "Clear Selection";
				pBtnClrSelEdge->SetTitle(strClearSelection);
				pBtnClrSelEdge->SetIconName("I_ClearSelection1");
				AddAnalyseNotificationCB(pBtnClrSelEdge, pBtnClrSelEdge->GetMenuIActivateNotification(), (CATCommandMethod)& MRFPointVentCmd::OnCtxMenuClearDualEdgeFirst, "ClearSelection");
			}
