//-------------------------------------------------------------------------
// OnCtxMenuClearDualEdgeFirst ()
// Launched when Context menu on Dual Edge First Reference Edge Selector is clicked
//-------------------------------------------------------------------------
void MRFPointVentCmd::OnCtxMenuClearDualEdgeFirst(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	char * pstrAction = (char *)iUsefulData;

	CATString strAction(pstrAction);

	if (!!_pMRFPointVentDlg && 0 == strAction.Compare("ClearSelection"))
	{
		CATDlgSelectorList* pSelectorListEdge = _pMRFPointVentDlg->GetDualEdgeRefEdgeFirst();

		if (NULL != pSelectorListEdge && NULL != _pDualEdgeRefEdgeFirstPathElement)
		{
			ClearSelection(_pDualEdgeRefEdgeFirstPathElement, pSelectorListEdge);
			_pDualEdgeRefEdgeFirstPathElement = NULL;
			_spDualEdgeFirstRefEdge = NULL_var;

			if (_EdgePreview)
				PreviewEdgeDirection(ipCommand, ipNotification, iUsefulData);
			_RevDir1 = 0;

			_ApplyDone = CATFalse;
		}

	}
	return;
}

