//-------------------------------------------------------------------------
// BuildCurveEdgeMethodUI ()
// Build Curve and Two Edge Method Vent Type Dialog Components
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::BuildCurveEdgeMethodUI(CATDialogState *& ipInitialState)
{
	if (NULL != ipInitialState && NULL != _pSurfaceTargetState)
	{
		CATListOfCATString ListEdgeTypes = GetEdgeOrCurveSelectorTypes();

		_pCurveEdgeRefCurvePathElementAgent = new CATPathElementAgent("CurveEdgeRefCurvePathElementAgent");
		if (_pCurveEdgeRefCurvePathElementAgent)
		{
			_pCurveEdgeRefCurvePathElementAgent->SetOrderedTypeList(ListEdgeTypes);
			_pCurveEdgeRefCurvePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pCurveEdgeRefCurveDialogAgent = new CATDialogAgent("CurveEdgeRefCurveDialogAgent");
		if (_pCurveEdgeRefCurveDialogAgent)
		{
			CATDlgSelectorList* pCurveEdgeRefCurveSelector = NULL;
			pCurveEdgeRefCurveSelector = _pMRFPointVentDlg->GetCurveEdgeReferenceCurve();
			if (NULL != pCurveEdgeRefCurveSelector)
			{
				_pCurveEdgeRefCurveDialogAgent->AcceptOnNotify(pCurveEdgeRefCurveSelector, pCurveEdgeRefCurveSelector->GetListSelectNotification());
			}
		}
		_pCurveEdgeRefCurveCtxMenuDlgAgent = new CATDialogAgent("CurveEdgeRefCurveCtxMenuDlgAgent");
		if (_pCurveEdgeRefCurveCtxMenuDlgAgent)
		{
			CATDlgContextualMenu * pCtxMenuRefCurve = _pMRFPointVentDlg->GetCurveEdgeRefCurveCtxMenu();
			if (pCtxMenuRefCurve)
			{
				_pCurveEdgeRefCurveCtxMenuDlgAgent->AcceptOnNotify(pCtxMenuRefCurve, pCtxMenuRefCurve->GetVisibilityNotification());
			}
		}
		_pCurveEdgeRefEdgeFirstPathElementAgent = new CATPathElementAgent("CurveEdgeRefEdgeFirstPathElementAgent");
		if (_pCurveEdgeRefEdgeFirstPathElementAgent)
		{
			_pCurveEdgeRefEdgeFirstPathElementAgent->SetOrderedTypeList(ListEdgeTypes);
			_pCurveEdgeRefEdgeFirstPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pCurveEdgeRefEdgeFirstDialogAgent = new CATDialogAgent("CurveEdgeRefEdgeFirstDialogAgent");
		if (_pCurveEdgeRefEdgeFirstDialogAgent)
		{
			CATDlgSelectorList* pCurveEdgeRefEdgeFirstSelector = NULL;
			pCurveEdgeRefEdgeFirstSelector = _pMRFPointVentDlg->GetCurveEdgeFirstEdge();
			if (NULL != pCurveEdgeRefEdgeFirstSelector)
			{
				_pCurveEdgeRefEdgeFirstDialogAgent->AcceptOnNotify(pCurveEdgeRefEdgeFirstSelector, pCurveEdgeRefEdgeFirstSelector->GetListSelectNotification());
			}
		}
		_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent = new CATDialogAgent("CurveEdgeRefEdgeFirstCtxMenuDlgAgent");
		if (_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent)
		{
			CATDlgContextualMenu * pCtxMenuRefEdgeFirst = _pMRFPointVentDlg->GetCurveEdgeReffEdgeFirstCtxMenu();
			if (pCtxMenuRefEdgeFirst)
			{
				_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent->AcceptOnNotify(pCtxMenuRefEdgeFirst, pCtxMenuRefEdgeFirst->GetVisibilityNotification());
			}
		}

		_pCurveEdgeRefEdgeSecondPathElementAgent = new CATPathElementAgent("CurveEdgeRefEdgeFirstPathElementAgent");
		if (_pCurveEdgeRefEdgeSecondPathElementAgent)
		{
			_pCurveEdgeRefEdgeSecondPathElementAgent->SetOrderedTypeList(ListEdgeTypes);
			_pCurveEdgeRefEdgeSecondPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pCurveEdgeRefEdgeSecondDialogAgent = new CATDialogAgent("CurveEdgeRefEdgeSecondDialogAgent");
		if (_pCurveEdgeRefEdgeSecondDialogAgent)
		{
			CATDlgSelectorList* pCurveEdgeRefEdgeSecondSelector = NULL;
			pCurveEdgeRefEdgeSecondSelector = _pMRFPointVentDlg->GetCurveEdgeSecondEdge();
			if (NULL != pCurveEdgeRefEdgeSecondSelector)
			{
				_pCurveEdgeRefEdgeSecondDialogAgent->AcceptOnNotify(pCurveEdgeRefEdgeSecondSelector, pCurveEdgeRefEdgeSecondSelector->GetListSelectNotification());
			}
		}
		_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent = new CATDialogAgent("CurveEdgeRefEdgeSecondCtxMenuDlgAgent");
		if (_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent)
		{
			CATDlgContextualMenu * pCtxMenuRefEdgeSecond = _pMRFPointVentDlg->GetCurveEdgeReffEdgeSecondCtxMenu();
			if (pCtxMenuRefEdgeSecond)
			{
				_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent->AcceptOnNotify(pCtxMenuRefEdgeSecond, pCtxMenuRefEdgeSecond->GetVisibilityNotification());
			}
		}

		CATDlgPushButton* pPushButtonDir = NULL;
		pPushButtonDir = _pMRFPointVentDlg->GetCurveEdgeOffsetDir();
		if (NULL != pPushButtonDir)
		{
			AddAnalyseNotificationCB(pPushButtonDir, pPushButtonDir->GetPushBActivateNotification(), (CATCommandMethod)&MRFPointVentCmd::PushReverseDirection1, NULL);
		}

		CATDlgSpinner* pOffsetDist = NULL;
		pOffsetDist = _pMRFPointVentDlg->GetCurveEdgeOffsetDistance();
		if (NULL != pOffsetDist)
		{
			AddAnalyseNotificationCB(pOffsetDist, pOffsetDist->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::SetPointVentModified, NULL);
		}

		CATDlgPushButton* pPreview = NULL;
		pPreview = _pMRFPointVentDlg->GetCurveEdgePreview();
		if (NULL != pPreview)
		{
			AddAnalyseNotificationCB(pPreview, pPreview->GetPushBActivateNotification(), (CATCommandMethod)&MRFPointVentCmd::PreviewEdgeDirection, NULL);
		}

		CATDlgSpinner* NbOfDivisions = NULL;
		NbOfDivisions = _pMRFPointVentDlg->GetCurveEdgeNbOfDivisions();
		if (NULL != NbOfDivisions)
		{
			AddAnalyseNotificationCB(NbOfDivisions, NbOfDivisions->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::SetPointVentModified, NULL);
		}

		ipInitialState->AddDialogAgent(_pCurveEdgeRefCurveDialogAgent);
		ipInitialState->AddDialogAgent(_pCurveEdgeRefCurveCtxMenuDlgAgent);
		ipInitialState->AddDialogAgent(_pCurveEdgeRefEdgeFirstDialogAgent);
		ipInitialState->AddDialogAgent(_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent);
		ipInitialState->AddDialogAgent(_pCurveEdgeRefEdgeSecondDialogAgent);
		ipInitialState->AddDialogAgent(_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent);

		_pSurfaceTargetState->AddDialogAgent(_pCurveEdgeRefCurveDialogAgent);

		CATDialogState * pCurveReferenceCurveState = AddDialogState("CurveReferenceCurveState");
		pCurveReferenceCurveState->AddDialogAgent(_pCurveEdgeRefCurveDialogAgent);
		pCurveReferenceCurveState->AddDialogAgent(_pCurveEdgeRefCurvePathElementAgent);
		pCurveReferenceCurveState->AddDialogAgent(_pCurveEdgeRefCurveCtxMenuDlgAgent);
		pCurveReferenceCurveState->AddDialogAgent(_pRefSurfaceDialogAgent);
		pCurveReferenceCurveState->AddDialogAgent(_pRefSurfaceCtxMenuDlgAgent);
		pCurveReferenceCurveState->AddDialogAgent(_pCurveEdgeRefEdgeFirstDialogAgent);
		pCurveReferenceCurveState->AddDialogAgent(_pCurveEdgeRefEdgeSecondDialogAgent);
		pCurveReferenceCurveState->AddDialogAgent(_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent);
		pCurveReferenceCurveState->AddDialogAgent(_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent);


		CATDialogState * pCurveReferenceEdgeFirstState = AddDialogState("CurveReferenceEdgeFirstState");
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pCurveEdgeRefEdgeFirstDialogAgent);
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pCurveEdgeRefEdgeFirstPathElementAgent);
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent);
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pRefSurfaceDialogAgent);
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pRefSurfaceCtxMenuDlgAgent);
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pCurveEdgeRefCurveDialogAgent);
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pCurveEdgeRefEdgeSecondDialogAgent);
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pCurveEdgeRefCurveCtxMenuDlgAgent);
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent);
		pCurveReferenceEdgeFirstState->AddDialogAgent(_pCurveEdgeRefCurvePathElementAgent);

		CATDialogState * pCurveReferenceEdgeSecondState = AddDialogState("CurveReferenceEdgeSecondState");
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pCurveEdgeRefEdgeSecondDialogAgent);
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pCurveEdgeRefEdgeSecondPathElementAgent);
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent);
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pRefSurfaceDialogAgent);
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pRefSurfaceCtxMenuDlgAgent);
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pCurveEdgeRefCurveDialogAgent);
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pCurveEdgeRefEdgeFirstDialogAgent);
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pCurveEdgeRefCurveCtxMenuDlgAgent);
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent);
		pCurveReferenceEdgeSecondState->AddDialogAgent(_pCurveEdgeRefEdgeFirstPathElementAgent);


		AddTransition(pCurveReferenceCurveState, ipInitialState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelectorList));
		AddTransition(pCurveReferenceEdgeFirstState, ipInitialState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelectorList));
		AddTransition(pCurveReferenceEdgeSecondState, ipInitialState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelectorList));
		AddTransition(pCurveReferenceCurveState, ipInitialState, IsOutputSetCondition(_pRefSurfaceCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuSurfaceSelection));
		AddTransition(pCurveReferenceEdgeFirstState, ipInitialState, IsOutputSetCondition(_pRefSurfaceCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuSurfaceSelection));
		AddTransition(pCurveReferenceEdgeSecondState, ipInitialState, IsOutputSetCondition(_pRefSurfaceCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuSurfaceSelection));


		// Reference Curve Selection Transitions
		{
			AddTransition(ipInitialState, pCurveReferenceCurveState, IsOutputSetCondition(_pCurveEdgeRefCurveDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeRefCurveSelectorList));
			AddTransition(_pSurfaceTargetState, pCurveReferenceCurveState, IsOutputSetCondition(_pCurveEdgeRefCurveDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeRefCurveSelectorList));
			AddTransition(pCurveReferenceCurveState, pCurveReferenceCurveState, IsOutputSetCondition(_pCurveEdgeRefCurveDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeRefCurveSelectorList));
			AddTransition(pCurveReferenceEdgeFirstState, pCurveReferenceCurveState, IsOutputSetCondition(_pCurveEdgeRefCurveDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeRefCurveSelectorList));
			AddTransition(pCurveReferenceEdgeSecondState, pCurveReferenceCurveState, IsOutputSetCondition(_pCurveEdgeRefCurveDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeRefCurveSelectorList));

			AddTransition(pCurveReferenceCurveState, pCurveReferenceEdgeFirstState, IsOutputSetCondition(_pCurveEdgeRefCurvePathElementAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeRefCurveSelection));

			AddTransition(ipInitialState, pCurveReferenceCurveState, IsOutputSetCondition(_pCurveEdgeRefCurveCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeCurveSelector));
			AddTransition(pCurveReferenceCurveState, pCurveReferenceCurveState, IsOutputSetCondition(_pCurveEdgeRefCurveCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeCurveSelector));
			AddTransition(pCurveReferenceEdgeFirstState, pCurveReferenceCurveState, IsOutputSetCondition(_pCurveEdgeRefCurveCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeCurveSelector));
			AddTransition(pCurveReferenceEdgeSecondState, pCurveReferenceCurveState, IsOutputSetCondition(_pCurveEdgeRefCurveCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeCurveSelector));

		}


		// First Reference Edge Selection Transitions
		{
			AddTransition(ipInitialState, pCurveReferenceEdgeFirstState, IsOutputSetCondition(_pCurveEdgeRefEdgeFirstDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeFirstRefEdgeSelectorList));
			AddTransition(pCurveReferenceCurveState, pCurveReferenceEdgeFirstState, IsOutputSetCondition(_pCurveEdgeRefEdgeFirstDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeFirstRefEdgeSelectorList));
			AddTransition(pCurveReferenceEdgeFirstState, pCurveReferenceEdgeFirstState, IsOutputSetCondition(_pCurveEdgeRefEdgeFirstDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeFirstRefEdgeSelectorList));
			AddTransition(pCurveReferenceEdgeSecondState, pCurveReferenceEdgeFirstState, IsOutputSetCondition(_pCurveEdgeRefEdgeFirstDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeFirstRefEdgeSelectorList));

			AddTransition(pCurveReferenceEdgeFirstState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeFirstPathElementAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeFirstRefEdgeSelection));

			AddTransition(ipInitialState, pCurveReferenceEdgeFirstState, IsOutputSetCondition(_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeFirstEdgeSelector));
			AddTransition(pCurveReferenceCurveState, pCurveReferenceEdgeFirstState, IsOutputSetCondition(_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeFirstEdgeSelector));
			AddTransition(pCurveReferenceEdgeFirstState, pCurveReferenceEdgeFirstState, IsOutputSetCondition(_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeFirstEdgeSelector));
			AddTransition(pCurveReferenceEdgeSecondState, pCurveReferenceEdgeFirstState, IsOutputSetCondition(_pCurveEdgeRefEdgeFirstCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeFirstEdgeSelector));

		}

		// Second Reference Edge Selection Transitions
		{
			AddTransition(ipInitialState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeSecondDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeSecondRefEdgeSelectorList));
			AddTransition(pCurveReferenceCurveState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeSecondDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeSecondRefEdgeSelectorList));
			AddTransition(pCurveReferenceEdgeFirstState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeSecondDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeSecondRefEdgeSelectorList));
			AddTransition(pCurveReferenceEdgeSecondState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeSecondDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeSecondRefEdgeSelectorList));

			AddTransition(pCurveReferenceEdgeSecondState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeSecondPathElementAgent), Action((ActionMethod)&MRFPointVentCmd::OnCurveEdgeSecondRefEdgeSelection));

			AddTransition(ipInitialState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeSecondEdgeSelector));
			AddTransition(pCurveReferenceCurveState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeSecondEdgeSelector));
			AddTransition(pCurveReferenceEdgeFirstState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeSecondEdgeSelector));
			AddTransition(pCurveReferenceEdgeSecondState, pCurveReferenceEdgeSecondState, IsOutputSetCondition(_pCurveEdgeRefEdgeSecondCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuCurveEdgeSecondEdgeSelector));

		}
	}
	return CATTrue;
}

//-------------------------------------------------------------------------
// OnCurveEdgeRefCurveSelectorList ()
// Launched when user selects the Selector List of Reference Curve in Curve and Two Edges Method Type
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::OnCurveEdgeRefCurveSelectorList(void * iData)
{
	if (NULL != _pHSO)
	{
		_pHSO->Empty();
		if (!!_pCurveEdgeRefCurvePathElement && 0 == _pHSO->IsMember(_pCurveEdgeRefCurvePathElement))
			_pHSO->AddElement(_pCurveEdgeRefCurvePathElement);
	}

	CATUnicodeString strString = "Select Reference Curve";
	if (!!_pMRFPointVentDlg)
	{
		_pMRFPointVentDlg->SetStatusBarText(strString);
		ClearAllSelections();

		CATDlgSelectorList* pRefCurve = NULL;
		pRefCurve = _pMRFPointVentDlg->GetCurveEdgeReferenceCurve();
		if (NULL != pRefCurve)
		{
			_pMRFPointVentDlg->SetFocusOnSelectorList(pRefCurve);

		}
	}
	if (!!_pCurveEdgeRefCurveDialogAgent)
		_pCurveEdgeRefCurveDialogAgent->InitializeAcquisition();

	return CATTrue;
}

//-------------------------------------------------------------------------
// OnCurveEdgeRefCurveSelection ()
// Launched when user selects a Reference Curve in Curve and Two Edges Method
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::OnCurveEdgeRefCurveSelection(void * iData)
{
	if (!!_pMRFPointVentDlg && NULL != _pCurveEdgeRefCurvePathElementAgent)
	{
		_pCurveEdgeRefCurvePathElement = _pCurveEdgeRefCurvePathElementAgent->GetValue();

		CATDlgSelectorList* pReferenceCurve = _pMRFPointVentDlg->GetCurveEdgeReferenceCurve();
		CATDlgSelectorList* pTargetDlgEdge = _pMRFPointVentDlg->GetCurveEdgeFirstEdge();

		if (!!_pCurveEdgeRefCurvePathElement && NULL != pReferenceCurve && NULL != pTargetDlgEdge)
		{
			CATIMmiMechanicalFeature_var spFeatureObject;
			BuildFromPathElement(_pCurveEdgeRefCurvePathElement, pReferenceCurve, spFeatureObject);

			double NbOfDivisions = _pMRFPointVentDlg->GetSelectedNbOfDivisions(2);
			int sel = 1;

			_RevDir1 = 0;
			if (_EdgePreview)
				PreviewEdgeDirection();

			if (!ValidateSelectedEdge(spFeatureObject, NbOfDivisions))
			{
				CATUnicodeString strMessage = "Selected Curve does not completely lie on the selected Surface.\n";
				strMessage.Append("Please reselect Input curve.");
				ShowErrorMessage(strMessage);

				ClearSelection(_pCurveEdgeRefCurvePathElement, pReferenceCurve);
				_pCurveEdgeRefCurvePathElement = NULL;
				_spCurveEdgeRefCurve = NULL_var;
				_pMRFPointVentDlg->SetFocusOnSelectorList(pReferenceCurve);
				pReferenceCurve->SetSelect(&sel, 1, 1);
				_ApplyDone = CATFalse;
			}
			else
			{
				if (NULL_var != _spCurveEdgeRefCurve)
				{
					_spCurveEdgeRefCurve = NULL_var;
				}
				_spCurveEdgeRefCurve = spFeatureObject;
				pTargetDlgEdge->SetSelect(&sel, 1, 1);
				PreviewEdgeDirection();
			}

		}
	}

	if (!!_pCurveEdgeRefCurvePathElementAgent)
		_pCurveEdgeRefCurvePathElementAgent->InitializeAcquisition();


	return CATTrue;
}

