//-------------------------------------------------------------------------
// OnCtxMenuClearCurveEdgeCurve ()
// Launched when Context menu on Curve and Two Edges Reference Curve Clear Selection is clicked
//-------------------------------------------------------------------------
void MRFPointVentCmd::OnCtxMenuClearCurveEdgeCurve(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	char * pstrAction = (char *)iUsefulData;

	CATString strAction(pstrAction);

	if (!!_pMRFPointVentDlg && 0 == strAction.Compare("ClearSelection"))
	{
		CATDlgSelectorList* pRefCurve = _pMRFPointVentDlg->GetCurveEdgeReferenceCurve();
		if (NULL != pRefCurve && NULL != _pCurveEdgeRefCurvePathElement)
		{
			ClearSelection(_pCurveEdgeRefCurvePathElement, pRefCurve);
			pRefCurve->ClearLine();
			pRefCurve->SetLine("No Curve Selected");
			_pCurveEdgeRefCurvePathElement = NULL;
			_spCurveEdgeRefCurve = NULL_var;

			if (_EdgePreview)
				PreviewEdgeDirection(ipCommand, ipNotification, iUsefulData);

			_RevDir1 = 0;
		}
		_ApplyDone = CATFalse;

	}
	return;
}

