//-------------------------------------------------------------------------
// BuildCurveEdgeMethodUI ()
// Build Curve and Two Edge Method Vent Type Dialog Components
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::BuildEdgeVentMethodUI(CATDialogState *& ipInitialState)
{
	if (NULL != ipInitialState && NULL != _pSurfaceTargetState)
	{
		CATListOfCATString ListEdgeTypes = GetEdgeOrCurveSelectorTypes();

		_pEdgeVentRefEdgePathElementAgent = new CATPathElementAgent("EdgeVentRefEdgePathElementAgent");
		if (_pEdgeVentRefEdgePathElementAgent)
		{
			_pEdgeVentRefEdgePathElementAgent->SetOrderedTypeList(ListEdgeTypes);
			_pEdgeVentRefEdgePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pEdgeVentRefEdgeDialogAgent = new CATDialogAgent("EdgeVentRefEdgeDialogAgent");
		if (_pEdgeVentRefEdgeDialogAgent)
		{
			CATDlgSelectorList* pEdgeVentRefEdgeSelector = NULL;
			pEdgeVentRefEdgeSelector = _pMRFPointVentDlg->GetEdgeVentReferenceEdge();
			if (NULL != pEdgeVentRefEdgeSelector)
			{
				_pEdgeVentRefEdgeDialogAgent->AcceptOnNotify(pEdgeVentRefEdgeSelector, pEdgeVentRefEdgeSelector->GetListSelectNotification());
			}
		}
		_pEdgeVentRefEdgeCtxMenuDlgAgent = new CATDialogAgent("EdgeVentRefEdgeCtxMenuDlgAgent");
		if (_pEdgeVentRefEdgeCtxMenuDlgAgent)
		{
			CATDlgContextualMenu * pCtxMenuRefEdge = _pMRFPointVentDlg->GetEdgeVentRefEdgeCtxMenu();
			if (pCtxMenuRefEdge)
			{
				_pEdgeVentRefEdgeCtxMenuDlgAgent->AcceptOnNotify(pCtxMenuRefEdge, pCtxMenuRefEdge->GetVisibilityNotification());
			}
		}

		_pEdgeVentRefVentPathElementAgent = new CATPathElementAgent("EdgeVentRefVentPathElementAgent");
		if (_pEdgeVentRefVentPathElementAgent)
		{
			_pEdgeVentRefVentPathElementAgent->SetOrderedElementType("MRFIPointVent");
			_pEdgeVentRefVentPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pEdgeVentRefVentDialogAgent = new CATDialogAgent("CurveEdgeRefEdgeFirstDialogAgent");
		if (_pEdgeVentRefVentDialogAgent)
		{
			CATDlgSelectorList* pEdgeVentRefVent = NULL;
			pEdgeVentRefVent = _pMRFPointVentDlg->GetEdgeVentReferenceVent();
			if (NULL != pEdgeVentRefVent)
			{
				_pEdgeVentRefVentDialogAgent->AcceptOnNotify(pEdgeVentRefVent, pEdgeVentRefVent->GetListSelectNotification());
			}
		}
		_pEdgeVentRefVentCtxMenuDlgAgent = new CATDialogAgent("CurveEdgeRefEdgeFirstCtxMenuDlgAgent");
		if (_pEdgeVentRefVentCtxMenuDlgAgent)
		{
			CATDlgContextualMenu * pCtxMenuRefVent = _pMRFPointVentDlg->GetEdgeVentRefVentCtxMenu();
			if (pCtxMenuRefVent)
			{
				_pEdgeVentRefVentCtxMenuDlgAgent->AcceptOnNotify(pCtxMenuRefVent, pCtxMenuRefVent->GetVisibilityNotification());
			}
		}

		CATDlgPushButton* pPushButtonDir = NULL;
		pPushButtonDir = _pMRFPointVentDlg->GetEdgeVentOffsetDir();
		if (NULL != pPushButtonDir)
		{
			AddAnalyseNotificationCB(pPushButtonDir, pPushButtonDir->GetPushBActivateNotification(), (CATCommandMethod)&MRFPointVentCmd::PushReverseDirection1, NULL);
		}

		CATDlgSpinner* pOffsetDist = NULL;
		pOffsetDist = _pMRFPointVentDlg->GetEdgeVentOffsetDistance();
		if (NULL != pOffsetDist)
		{
			AddAnalyseNotificationCB(pOffsetDist, pOffsetDist->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::SetPointVentModified, NULL);
		}

		CATDlgPushButton* pPreview = NULL;
		pPreview = _pMRFPointVentDlg->GetEdgeVentPreview();
		if (NULL != pPreview)
		{
			AddAnalyseNotificationCB(pPreview, pPreview->GetPushBActivateNotification(), (CATCommandMethod)&MRFPointVentCmd::PreviewEdgeDirection, NULL);
		}

		CATDlgCheckButton* pAxisCheck = _pMRFPointVentDlg->GetEdgeVentAxisCheck();
		if (NULL != pAxisCheck)
		{
			CATCommandClientData EdgeVentData("EdgeVent");
			AddAnalyseNotificationCB(pAxisCheck, pAxisCheck->GetChkBModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::OnRadioChange, EdgeVentData);
		}

		CATDlgCombo * pEdgeVentAxisCombo = _pMRFPointVentDlg->GetEdgeVentAxis();
		if (NULL != pEdgeVentAxisCombo)
		{
			AddAnalyseNotificationCB(pEdgeVentAxisCombo, pEdgeVentAxisCombo->GetComboSelectNotification(), (CATCommandMethod)&MRFPointVentCmd::SetPointVentModified, NULL);
		}

		ipInitialState->AddDialogAgent(_pEdgeVentRefEdgeDialogAgent);
		ipInitialState->AddDialogAgent(_pEdgeVentRefEdgePathElementAgent);
		ipInitialState->AddDialogAgent(_pEdgeVentRefEdgeCtxMenuDlgAgent);
		ipInitialState->AddDialogAgent(_pEdgeVentRefVentDialogAgent);
		ipInitialState->AddDialogAgent(_pEdgeVentRefVentPathElementAgent);
		ipInitialState->AddDialogAgent(_pEdgeVentRefVentCtxMenuDlgAgent);

		_pSurfaceTargetState->AddDialogAgent(_pEdgeVentRefEdgeDialogAgent);

		CATDialogState * pEdgeVentRefEdgeState = AddDialogState("EdgeVentRefEdgeState");
		pEdgeVentRefEdgeState->AddDialogAgent(_pEdgeVentRefEdgeDialogAgent);
		pEdgeVentRefEdgeState->AddDialogAgent(_pEdgeVentRefEdgePathElementAgent);
		pEdgeVentRefEdgeState->AddDialogAgent(_pEdgeVentRefEdgeCtxMenuDlgAgent);
		pEdgeVentRefEdgeState->AddDialogAgent(_pRefSurfaceDialogAgent);
		pEdgeVentRefEdgeState->AddDialogAgent(_pRefSurfaceCtxMenuDlgAgent);
		pEdgeVentRefEdgeState->AddDialogAgent(_pEdgeVentRefVentDialogAgent);
		pEdgeVentRefEdgeState->AddDialogAgent(_pEdgeVentRefVentCtxMenuDlgAgent);


		CATDialogState * pEdgeVentRefVentState = AddDialogState("EdgeVentRefVentState");
		pEdgeVentRefVentState->AddDialogAgent(_pEdgeVentRefVentDialogAgent);
		pEdgeVentRefVentState->AddDialogAgent(_pEdgeVentRefVentCtxMenuDlgAgent);
		pEdgeVentRefVentState->AddDialogAgent(_pEdgeVentRefVentPathElementAgent);
		pEdgeVentRefVentState->AddDialogAgent(_pRefSurfaceDialogAgent);
		pEdgeVentRefVentState->AddDialogAgent(_pRefSurfaceCtxMenuDlgAgent);
		pEdgeVentRefVentState->AddDialogAgent(_pEdgeVentRefEdgeDialogAgent);
		pEdgeVentRefVentState->AddDialogAgent(_pEdgeVentRefEdgeCtxMenuDlgAgent);
		pEdgeVentRefVentState->AddDialogAgent(_pEdgeVentRefEdgePathElementAgent);


		AddTransition(pEdgeVentRefEdgeState, ipInitialState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelectorList));
		AddTransition(pEdgeVentRefVentState, ipInitialState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelectorList));
		AddTransition(pEdgeVentRefEdgeState, ipInitialState, IsOutputSetCondition(_pRefSurfaceCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuSurfaceSelection));
		AddTransition(pEdgeVentRefVentState, ipInitialState, IsOutputSetCondition(_pRefSurfaceCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuSurfaceSelection));



		// Reference Edge Selection Transitions
		{
			AddTransition(ipInitialState, pEdgeVentRefEdgeState, IsOutputSetCondition(_pEdgeVentRefEdgeDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnEdgeVentRefEdgeSelectorList));
			AddTransition(_pSurfaceTargetState, pEdgeVentRefEdgeState, IsOutputSetCondition(_pEdgeVentRefEdgeDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnEdgeVentRefEdgeSelectorList));
			AddTransition(pEdgeVentRefEdgeState, pEdgeVentRefEdgeState, IsOutputSetCondition(_pEdgeVentRefEdgeDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnEdgeVentRefEdgeSelectorList));
			AddTransition(pEdgeVentRefVentState, pEdgeVentRefEdgeState, IsOutputSetCondition(_pEdgeVentRefEdgeDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnEdgeVentRefEdgeSelectorList));

			AddTransition(pEdgeVentRefEdgeState, pEdgeVentRefVentState, IsOutputSetCondition(_pEdgeVentRefEdgePathElementAgent), Action((ActionMethod)&MRFPointVentCmd::OnEdgeVentRefEdgeSelection));

			AddTransition(ipInitialState, pEdgeVentRefEdgeState, IsOutputSetCondition(_pEdgeVentRefEdgeCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuEdgeVentRefEdgeSelector));
			AddTransition(pEdgeVentRefEdgeState, pEdgeVentRefEdgeState, IsOutputSetCondition(_pEdgeVentRefEdgeCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuEdgeVentRefEdgeSelector));
			AddTransition(pEdgeVentRefVentState, pEdgeVentRefEdgeState, IsOutputSetCondition(_pEdgeVentRefEdgeCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuEdgeVentRefEdgeSelector));

		}


		// Reference Vent Selection Transitions
		{
			AddTransition(ipInitialState, pEdgeVentRefVentState, IsOutputSetCondition(_pEdgeVentRefVentDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnEdgeVentRefVentSelectorList));
			AddTransition(pEdgeVentRefEdgeState, pEdgeVentRefVentState, IsOutputSetCondition(_pEdgeVentRefVentDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnEdgeVentRefVentSelectorList));
			AddTransition(pEdgeVentRefVentState, pEdgeVentRefVentState, IsOutputSetCondition(_pEdgeVentRefVentDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnEdgeVentRefVentSelectorList));

			AddTransition(pEdgeVentRefVentState, pEdgeVentRefVentState, IsOutputSetCondition(_pEdgeVentRefVentPathElementAgent), Action((ActionMethod)&MRFPointVentCmd::OnEdgeVentRefVentSelection));

			AddTransition(ipInitialState, pEdgeVentRefVentState, IsOutputSetCondition(_pEdgeVentRefVentCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuEdgeVentRefVentSelector));
			AddTransition(pEdgeVentRefEdgeState, pEdgeVentRefVentState, IsOutputSetCondition(_pEdgeVentRefVentCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuEdgeVentRefVentSelector));
			AddTransition(pEdgeVentRefVentState, pEdgeVentRefVentState, IsOutputSetCondition(_pEdgeVentRefVentCtxMenuDlgAgent), Action((ActionMethod)&MRFPointVentCmd::OnCtxMenuEdgeVentRefVentSelector));

		}
	}
	return CATTrue;
}

