//-------------------------------------------------------------------------
// OnEdgeVentRefEdgeSelection ()
// Launched when user selects Reference Edge in Edge and Vent Method
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::OnEdgeVentRefEdgeSelection(void * iData)
{
	if (!!_pMRFPointVentDlg && NULL != _pEdgeVentRefEdgePathElementAgent)
	{
		_pEdgeVentRefEdgePathElement = _pEdgeVentRefEdgePathElementAgent->GetValue();
		int sel = 1;
		CATDlgSelectorList* pReferenceEdge = _pMRFPointVentDlg->GetEdgeVentReferenceEdge();
		CATDlgSelectorList* pTargetSelector = _pMRFPointVentDlg->GetEdgeVentReferenceVent();

		if (!!_pEdgeVentRefEdgePathElement && NULL != pReferenceEdge && NULL != pTargetSelector)
		{
			CATIMmiMechanicalFeature_var spFeatureObject;
			BuildFromPathElement(_pEdgeVentRefEdgePathElement, pReferenceEdge, spFeatureObject);

			_RevDir1 = 0;
			if (_EdgePreview)
				PreviewEdgeDirection();

			if (!ValidateSelectedEdge(spFeatureObject, 1))
			{
				CATUnicodeString strMessage = "Selected Edge does not completely lie on the selected Surface.\n";
				strMessage.Append("Please reselect Input Edge.");
				ShowErrorMessage(strMessage);

				ClearSelection(_pEdgeVentRefEdgePathElement, pReferenceEdge);
				_pEdgeVentRefEdgePathElement = NULL;
				_spEdgeVentRefEdge = NULL_var;
				_pMRFPointVentDlg->SetFocusOnSelectorList(pReferenceEdge);
				pReferenceEdge->SetSelect(&sel, 1, 1);
				_ApplyDone = CATFalse;
			}
			else
			{
				if (NULL_var != _spEdgeVentRefEdge)
				{
					_spEdgeVentRefEdge = NULL_var;
				}
				_spEdgeVentRefEdge = spFeatureObject;
				pTargetSelector->SetSelect(&sel, 1, 1);
				PreviewEdgeDirection();
			}

		}
	}

	if (!!_pEdgeVentRefEdgePathElementAgent)
		_pEdgeVentRefEdgePathElementAgent->InitializeAcquisition();


	return CATTrue;
}

