//-------------------------------------------------------------------------
// OnEdgeVentRefVentSelection ()
// Launched when user selects Reference Vent in Edge and Vent Method
//-------------------------------------------------------------------------
CATBoolean MRFPointVentCmd::OnEdgeVentRefVentSelection(void * iData)
{
	if (!!_pMRFPointVentDlg && NULL != _pEdgeVentRefVentPathElementAgent)
	{
		_pEdgeVentRefVentPathElement = _pEdgeVentRefVentPathElementAgent->GetValue();

		CATDlgSelectorList* pReferenceVent = _pMRFPointVentDlg->GetEdgeVentReferenceVent();

		if (!!_pEdgeVentRefVentPathElement && NULL != pReferenceVent)
		{
			CATIMmiMechanicalFeature_var spVentFeatureObject;
			//BuildFromPathElement(_pEdgeVentRefVentPathElement, pReferenceVent, spFeatureObject);
			CATUnicodeString strVentName = GetObjectNameFromPathElement(_pEdgeVentRefVentPathElement, spVentFeatureObject, 0);

			if (NULL_var != spVentFeatureObject)
			{
				_spEdgeVentRefVent = spVentFeatureObject;
			}

			if (!ValidateSelectedVent(spVentFeatureObject))
			{
				CATUnicodeString strMessage = "Selected Vent does not completely lie on the selected Surface.\n";
				strMessage.Append("Please reselect Input Vent.");
				ShowErrorMessage(strMessage);

				ClearSelection(_pEdgeVentRefVentPathElement, pReferenceVent);
				_pEdgeVentRefVentPathElement = NULL;
				_spEdgeVentRefVent = NULL_var;
				_pMRFPointVentDlg->SetFocusOnSelectorList(pReferenceVent);

				_ApplyDone = CATFalse;
			}
			else
			{
				if (NULL_var != _spEdgeVentRefVent)
				{
					_spEdgeVentRefVent = NULL_var;
				}
				_spEdgeVentRefVent = spVentFeatureObject;
				if (_bEdgeVentAxis)
				{
					if (_SecondEdgePreview)
						PreviewSecondEdgeDirection();
					PreviewSecondEdgeDirection();
				}				

				if (!!_pMRFPointVentDlg)
				{
					CATDlgSelectorList* pRefVentSelector = _pMRFPointVentDlg->GetEdgeVentReferenceVent();
					if (NULL != pRefVentSelector)
					{

						pRefVentSelector->ClearLine();
						pRefVentSelector->SetLine(strVentName);
						_pMRFPointVentDlg->SetFocusOnSelectorList(pRefVentSelector);
					}
				}

				if (NULL != _pHSO)
				{
					_pHSO->Empty();
					if (NULL != _pEdgeVentRefVentPathElement && 0 == _pHSO->IsMember(_pEdgeVentRefVentPathElement))
						_pHSO->AddElement(_pEdgeVentRefVentPathElement);
				}

			}

		}
	}

	if (!!_pEdgeVentRefVentPathElementAgent)
		_pEdgeVentRefVentPathElementAgent->InitializeAcquisition();


	return CATTrue;
}

