CATBoolean MRFPointVentCmd::BuildSegmentVentUI(CATDialogState *& ipInitialState)
{
	if (NULL != ipInitialState)
	{
		_pSegmentVentRefVentDialogAgent = new CATDialogAgent("SegmentVentRefVentDialogAgent");
		if (!!_pSegmentVentRefVentDialogAgent)
		{
			CATDlgSelectorList* pRefVent = _pMRFPointVentDlg->GetSegmentVentReferenceVent();
			if (NULL != pRefVent)
			{
				_pSegmentVentRefVentDialogAgent->AcceptOnNotify(pRefVent, pRefVent->GetListSelectNotification());
			}

		}
		_pSegmentVentCtxMenuDialogAgent = new CATDialogAgent("SegmentVentCtxMenuDialogAgent");
		if (!!_pSegmentVentCtxMenuDialogAgent)
		{
			CATDlgContextualMenu* pVentCtxMenu = _pMRFPointVentDlg->GetSegmentVentCtxMenu();
			if (NULL != pVentCtxMenu)
			{
				_pSegmentVentCtxMenuDialogAgent->AcceptOnNotify(pVentCtxMenu, pVentCtxMenu->GetVisibilityNotification());
			}
		}

		ipInitialState->AddDialogAgent(_pSegmentVentRefVentDialogAgent);

		CATDialogState * pSegmentVentState = AddDialogState("SegmentVentState");
		pSegmentVentState->AddDialogAgent(_pSegmentVentRefVentDialogAgent);
		pSegmentVentState->AddDialogAgent(_pSegmentVentCtxMenuDialogAgent);
		pSegmentVentState->AddDialogAgent(_pRefSurfaceDialogAgent);

		AddTransition(ipInitialState, pSegmentVentState, IsOutputSetCondition(_pSegmentVentRefVentDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSegmentReferenceVentSelectorList));
		AddTransition(pSegmentVentState, pSegmentVentState, IsOutputSetCondition(_pSegmentVentRefVentDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSegmentReferenceVentSelectorList));

		AddTransition(pSegmentVentState, pSegmentVentState, IsOutputSetCondition(_pSegmentVentCtxMenuDialogAgent), Action((ActionMethod)&MRFPointVentCmd::BuildSegmentVentCtxMenu));

		AddTransition(pSegmentVentState, ipInitialState, IsOutputSetCondition(_pRefSurfaceDialogAgent), Action((ActionMethod)&MRFPointVentCmd::OnSurfaceSelectorList));


		CATDlgSpinner* pSegmentDeltaU = _pMRFPointVentDlg->GetSegmentDeltaU();
		if (!!pSegmentDeltaU)
		{
			AddAnalyseNotificationCB(pSegmentDeltaU, pSegmentDeltaU->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::SetPointVentModified, NULL);
		}

		CATDlgSpinner* pSegmentDeltaV = _pMRFPointVentDlg->GetSegmentVentDeltaV();
		if (!!pSegmentDeltaV)
		{
			AddAnalyseNotificationCB(pSegmentDeltaV, pSegmentDeltaV->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFPointVentCmd::SetPointVentModified, NULL);
		}

	}
	return CATTrue;
}

